const CONTINENTS = ['All','Africa','Asia','Europe','North America','South America','Antarctica'];
const MODES = [
  { id:'tells',   label:'Quick Tells', icon:'🔍', desc:'Identify from visual tells' },
  { id:'flag',    label:'Flag',        icon:'🏳️', desc:'Identify from the flag' },
  { id:'car',     label:'Google Car',  icon:'📷', desc:'Identify from camera/car' },
  { id:'lang',    label:'Language',    icon:'🔤', desc:'Identify from script/language' },
  { id:'mixups',  label:'Mix-ups',     icon:'⚖️', desc:'Compare two look-alike countries' },
  { id:'roads',   label:'Roads',       icon:'🛣️', desc:'Signs, bollards & road features' },
  { id:'spaced',  label:'Spaced Rep',  icon:'🔁', desc:'Weighted by your wrong answers' },
  { id:'deepdive',label:'Deep Dive',   icon:'📚', desc:'Study a country in full' },
];


const ROAD_SUBMODES = [
  { id:'all',     label:'All' },
  { id:'sign',    label:'Signs' },
  { id:'bollard', label:'Bollards' },
  { id:'lamp',    label:'Lamps' },
  { id:'post',    label:'Posts' },
];
function classifyRoadBullet(text) {
  const t = text.toLowerCase();
  if (/bollard/.test(t)) return 'bollard';
  if (/\blamp\b|street[- ]?light|lantern/.test(t)) return 'lamp';
  if (/\bpole\b|\bpost\b|utility[- ]?pole|pylon|telegraph/.test(t)) return 'post';
  if (/sign|direction|speed|\bstop\b|warning|chevron|motorway|yield|highway shield/.test(t)) return 'sign';
  return 'other';
}
function getRoadsBullets(country, subMode) {
  const b = country.roadsBullets || [];
  if (subMode === 'all') return b;
  return b.filter(x => classifyRoadBullet(x) === subMode);
}
function findImage(country, subMode) {
  const imgs = country.images || [];
  if (!imgs.length) return null;
  const kw = { bollard:'bollard', lamp:'lamp|light', post:'pole|post|pylon', sign:'sign|chevron|crossing|direction', all:'.' };
  const re = new RegExp(kw[subMode] || '.', 'i');
  const match = imgs.find(i => re.test(i.l));
  return match ? match.f : null;
}
// ─── UTILS ──────────────────────────────────────────────────────────────────
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function pickRandom(arr, n, exclude = new Set()) {
  const pool = arr.filter(x => !exclude.has(x));
  return shuffle(pool).slice(0, n);
}

function getPool(continent, difficulty, mode, roadsSubMode='all') {
  let pool = COUNTRIES;
  if (continent !== 'All') pool = pool.filter(c => c.continent === continent);
  if (difficulty === 'Easy') pool = pool.filter(c => MAJOR.has(c.name));
  if (mode === 'tells') pool = pool.filter(c => c.quickTells.length >= 3);
  if (mode === 'flag') pool = pool.filter(c => c.flag);
  if (mode === 'car') pool = pool.filter(c => c.googleCar || c.carBullets.length > 0);
  if (mode === 'lang') pool = pool.filter(c => c.languageScript || c.languageBullets.length > 0);
  if (mode === 'mixups') pool = pool.filter(c => c.mixups.length > 0);
  if (mode === 'roads') pool = pool.filter(c => getRoadsBullets(c, roadsSubMode).length >= 2);
  return pool;
}

function pickDistractors(correct, pool, n = 3) {
  const exclude = new Set([correct.name]);
  // prefer same continent
  let same = pool.filter(c => c.continent === correct.continent && !exclude.has(c.name));
  const picks = [];
  const fromSame = shuffle(same).slice(0, Math.min(n, same.length));
  picks.push(...fromSame);
  if (picks.length < n) {
    const rest = pool.filter(c => !exclude.has(c.name) && !picks.includes(c));
    picks.push(...shuffle(rest).slice(0, n - picks.length));
  }
  return picks.slice(0, n);
}

function makeChoices(correct, distractors) {
  const all = [correct, ...distractors];
  const shuffled = shuffle(all);
  return { choices: shuffled, correctIdx: shuffled.indexOf(correct) };
}

function sanitize(text, countryName) {
  if (!text || !countryName) return text;
  const escaped = countryName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // Match the country name + optional adjectival suffixes (e.g. Rwandan, Japanese, Brazilian)
  const re = new RegExp(escaped + '(?:n|an|ian|ese|i|ish|er|ers)?', 'gi');
  return text.replace(re, '[country]');
}

function generateQuestion(mode, pool, wrongHistory = {}, roadsSubMode = 'all') {
  if (!pool.length) return null;

  // Weighted random selection for spaced rep
  let target;
  if (mode === 'spaced' && Object.keys(wrongHistory).length > 0) {
    const weighted = [];
    for (const c of pool) {
      const w = (wrongHistory[c.id] || 0) + 1;
      for (let i = 0; i < w; i++) weighted.push(c);
    }
    target = weighted[Math.floor(Math.random() * weighted.length)];
  } else {
    target = pool[Math.floor(Math.random() * pool.length)];
  }

  const distractors = pickDistractors(target, pool, 3);
  const { choices, correctIdx } = makeChoices(target, distractors);
  
  const actualMode = mode === 'spaced' ? pickBestMode(target) : mode;

  let question = { target, choices, correctIdx, mode: actualMode };

  if (actualMode === 'flag') {
    question.display = { type: 'flag', content: target.flag };
    question.prompt = 'Which country does this flag belong to?';
    question.explanation = `${target.flag} ${target.name} (${target.continent})`;
  } else if (actualMode === 'tells') {
    const tells = shuffle(target.quickTells).slice(0, Math.min(4, target.quickTells.length)).map(s => sanitize(s, target.name));
    question.display = { type: 'bullets', content: tells };
    question.prompt = 'Which country do these quick tells describe?';
    question.explanation = target.quickTells.slice(0, 3).join(' • ');
  } else if (actualMode === 'car') {
    const content = target.carBullets.length > 0
      ? target.carBullets.slice(0, 4).map(s => sanitize(s, target.name))
      : [sanitize(target.googleCar, target.name)];
    question.display = { type: target.carBullets.length > 0 ? 'bullets' : 'prose', content };
    question.prompt = 'Which country does this Google Street View camera describe?';
    question.explanation = target.googleCar || target.carBullets.join(' • ');
  } else if (actualMode === 'lang') {
    const content = target.languageBullets.length > 0
      ? target.languageBullets.slice(0, 4).map(s => sanitize(s, target.name))
      : [sanitize(target.languageScript, target.name)];
    question.display = { type: target.languageBullets.length > 0 ? 'bullets' : 'prose', content };
    question.prompt = 'Which country uses this language or script?';
    question.explanation = target.languageScript || target.languageBullets.join(' • ');
  } else if (actualMode === 'roads') {
    const bullets = shuffle(getRoadsBullets(target, roadsSubMode)).slice(0, Math.min(4, getRoadsBullets(target, roadsSubMode).length));
    const img = findImage(target, roadsSubMode);
    question.display = { type: 'bullets', content: bullets.map(s => sanitize(s, target.name)), image: img };
    question.prompt = 'Which country has these roads and signs?';
    question.explanation = (target.roadsBullets || []).slice(0,3).join(' • ');
  } else if (actualMode === 'mixups') {
    const mu = target.mixups[Math.floor(Math.random() * target.mixups.length)];
    const clue = sanitize(mu.clue, target.name);
    question.display = { type: 'prose', content: [clue] };
    question.prompt = mu.country
      ? `This clue distinguishes a country from ${mu.country}. Which country does the clue describe?`
      : 'Which country does this distinguishing clue describe?';
    question.explanation = `${target.name}: ${target.quickTells.slice(0,2).join(' • ')}`;
    // Mix-ups: always make the look-alike country one of the wrong choices
    const lookalike = pool.find(c => c.name === mu.country);
    if (lookalike) {
      const exclude = new Set([target.name, mu.country]);
      const fillers = shuffle(pool.filter(c => !exclude.has(c.name))).slice(0, 2);
      const allChoices = shuffle([target, lookalike, ...fillers]);
      question.choices = allChoices;
      question.correctIdx = allChoices.indexOf(target);
    }
  }

  return question;
}

function pickBestMode(country) {
  const modes = [];
  if (country.flag) modes.push('flag','flag'); // double weight flags
  if (country.quickTells.length >= 3) modes.push('tells','tells');
  if (country.googleCar || country.carBullets.length) modes.push('car');
  if (country.languageScript || country.languageBullets.length) modes.push('lang');
  if (country.mixups.length) modes.push('mixups');
  if (!modes.length) return 'tells';
  return modes[Math.floor(Math.random() * modes.length)];
}

// ─── STORAGE ─────────────────────────────────────────────────────────────────
const STORAGE_KEY = 'geoguessr_study_v1';

function loadStats() {
  try {
    const s = localStorage.getItem(STORAGE_KEY);
    if (s) return JSON.parse(s);
  } catch {}
  return {
    totalAnswered: 0,
    totalCorrect: 0,
    modeScores: {},
    wrongHistory: {},
  };
}

function saveStats(stats) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(stats)); } catch {}
}

// ─── COMPONENTS ─────────────────────────────────────────────────────────────

function ModeButton({ mode, current, onClick, dark }) {
  const active = mode.id === current;
  return (
    <button
      onClick={() => onClick(mode.id)}
      className={`flex flex-col items-center gap-0.5 px-3 py-2 rounded-xl text-xs font-medium transition-all
        ${active
          ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30'
          : dark
            ? 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-gray-200'
            : 'bg-white text-gray-500 hover:bg-gray-100 hover:text-gray-800 border border-gray-200'
        }`}
    >
      <span className="text-base">{mode.icon}</span>
      <span>{mode.label}</span>
    </button>
  );
}

function FilterBar({ continent, setContinent, difficulty, setDifficulty, dark }) {
  const base = dark
    ? 'bg-gray-800 text-gray-300 border-gray-700'
    : 'bg-white text-gray-700 border-gray-300';
  return (
    <div className="flex flex-wrap gap-2 items-center">
      <select
        value={continent}
        onChange={e => setContinent(e.target.value)}
        className={`${base} border rounded-lg px-3 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500`}
      >
        {CONTINENTS.map(c => <option key={c} value={c}>{c}</option>)}
      </select>
      <div className="flex gap-1">
        {['All','Easy','Hard'].map(d => (
          <button
            key={d}
            onClick={() => setDifficulty(d)}
            className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all
              ${difficulty === d
                ? d === 'Easy' ? 'bg-blue-500 text-white'
                  : d === 'Hard' ? 'bg-orange-500 text-white'
                  : 'bg-emerald-500 text-white'
                : dark
                  ? 'bg-gray-800 text-gray-400 hover:bg-gray-700'
                  : 'bg-white text-gray-500 hover:bg-gray-100 border border-gray-200'
              }`}
          >
            {d}
          </button>
        ))}
      </div>
    </div>
  );
}

function DisplayImage({ src }) {
  if (!src) return null;
  return (
    <img
      src={src}
      alt="Visual clue"
      className="w-full rounded-xl mb-3 object-cover max-h-48"
    />
  );
}

function DisplayCard({ display, dark }) {
  if (!display) return null;
  const cardBg = dark ? 'bg-gray-800/60' : 'bg-gray-50';

  if (display.type === 'flag') {
    return (
      <div className="flex flex-col items-center justify-center py-8 gap-4">
        <div className="text-8xl select-none drop-shadow-lg">{display.content}</div>
      </div>
    );
  }

  if (display.type === 'bullets') {
    return (
      <div>
        <DisplayImage src={display.image} />
        <div className={`rounded-2xl p-5 ${cardBg} space-y-2`}>
          {(Array.isArray(display.content) ? display.content : [display.content]).map((item, i) => (
            <div key={i} className="flex gap-3">
              <span className="text-emerald-500 mt-0.5 shrink-0">▶</span>
              <span className={`text-sm leading-relaxed ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{item}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (display.type === 'prose') {
    return (
      <div>
        <DisplayImage src={display.image} />
        <div className={`rounded-2xl p-5 ${cardBg}`}>
          <p className={`text-sm leading-relaxed ${dark ? 'text-gray-300' : 'text-gray-700'}`}>
            {Array.isArray(display.content) ? display.content[0] : display.content}
          </p>
        </div>
      </div>
    );
  }

  return null;
}
function ChoiceGrid({ choices, correctIdx, selected, onSelect, dark, showResult, questionMode }) {
  return (
    <div className="grid grid-cols-2 gap-3">
      {choices.map((c, i) => {
        const isCorrect = i === correctIdx;
        const isSelected = i === selected;
        let style = dark
          ? 'bg-gray-800 border-gray-700 text-gray-200 hover:bg-gray-700 hover:border-gray-500'
          : 'bg-white border-gray-200 text-gray-800 hover:bg-gray-50 hover:border-gray-400';

        if (showResult) {
          if (isCorrect) style = 'bg-emerald-500/20 border-emerald-500 text-emerald-400';
          else if (isSelected && !isCorrect) style = 'bg-red-500/20 border-red-500 text-red-400';
          else style = dark
            ? 'bg-gray-800/50 border-gray-700/50 text-gray-500'
            : 'bg-gray-50 border-gray-200 text-gray-400';
        }

        return (
          <button
            key={i}
            onClick={() => !showResult && onSelect(i)}
            disabled={showResult}
            className={`border-2 rounded-2xl px-4 py-3 text-sm font-medium text-left transition-all
              flex items-center gap-3 ${style}
              ${!showResult ? 'cursor-pointer active:scale-95' : 'cursor-default'}`}
          >
            <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0
              ${dark ? 'bg-gray-700' : 'bg-gray-100'}`}>
              {String.fromCharCode(65 + i)}
            </span>
            <span className="flex items-center gap-2">
              {c.flag && questionMode !== 'flag' && <span>{c.flag}</span>}
              {c.name}
            </span>
            {showResult && isCorrect && <span className="ml-auto">✓</span>}
            {showResult && isSelected && !isCorrect && <span className="ml-auto">✗</span>}
          </button>
        );
      })}
    </div>
  );
}

function FeedbackPanel({ question, selected, dark }) {
  const correct = selected === question.correctIdx;
  return (
    <div className={`rounded-2xl p-4 border-2 ${
      correct
        ? 'bg-emerald-500/10 border-emerald-500/50'
        : 'bg-red-500/10 border-red-500/50'
    }`}>
      <div className="flex items-center gap-2 mb-2">
        <span className="text-xl">{correct ? '✅' : '❌'}</span>
        <span className={`font-bold ${correct ? 'text-emerald-400' : 'text-red-400'}`}>
          {correct ? 'Correct!' : `Wrong — it was ${question.target.flag} ${question.target.name}`}
        </span>
      </div>
      {question.explanation && (
        <p className={`text-xs leading-relaxed ${dark ? 'text-gray-400' : 'text-gray-600'}`}>
          {question.explanation}
        </p>
      )}
    </div>
  );
}

function ProgressBar({ current, total, dark }) {
  const pct = total > 0 ? Math.round((current / total) * 100) : 0;
  return (
    <div className={`w-full rounded-full h-2 ${dark ? 'bg-gray-700' : 'bg-gray-200'}`}>
      <div
        className="h-2 rounded-full bg-emerald-500 transition-all duration-500"
        style={{ width: `${pct}%` }}
      />
    </div>
  );
}

function SessionBar({ score, streak, qNum, dark }) {
  return (
    <div className="flex items-center justify-between text-sm">
      <div className="flex gap-4">
        <span className={dark ? 'text-gray-400' : 'text-gray-500'}>
          Score: <span className="font-bold text-emerald-500">{score.correct}/{score.total}</span>
        </span>
        {score.total > 0 && (
          <span className={dark ? 'text-gray-400' : 'text-gray-500'}>
            {Math.round((score.correct / score.total) * 100)}%
          </span>
        )}
      </div>
      {streak > 1 && (
        <span className="font-bold text-orange-400">🔥 {streak}</span>
      )}
    </div>
  );
}

// ─── DEEP DIVE ───────────────────────────────────────────────────────────────
function DeepDive({ pool, dark }) {
  const [selected, setSelected] = useState(pool[0]);
  const [tab, setTab] = useState('overview');

  useEffect(() => {
    if (!pool.find(c => c.id === selected?.id)) setSelected(pool[0]);
  }, [pool]);

  if (!pool.length) return (
    <div className={`text-center py-16 ${dark ? 'text-gray-500' : 'text-gray-400'}`}>
      No countries match your filters. Try changing the continent or difficulty.
    </div>
  );

  const c = selected;
  const tabs = ['overview','tells','language','roads','car','mixups'];
  const tabLabel = { overview:'Overview', tells:'Quick Tells', language:'Language', roads:'Roads', car:'Google Car', mixups:'Mix-ups' };

  const Section = ({ title, items, prose }) => {
    if (!items?.length && !prose) return null;
    return (
      <div className="space-y-2">
        <h4 className={`text-xs font-bold uppercase tracking-wider ${dark ? 'text-gray-500' : 'text-gray-400'}`}>{title}</h4>
        {prose && <p className={`text-sm leading-relaxed ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{prose}</p>}
        {items?.map((item, i) => (
          <div key={i} className="flex gap-3">
            <span className="text-emerald-500 mt-0.5 shrink-0 text-xs">▶</span>
            <span className={`text-sm leading-relaxed ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{item}</span>
          </div>
        ))}
      </div>
    );
  };

  return (
    <div className="space-y-4">
      <select
        value={selected?.id || ''}
        onChange={e => setSelected(pool.find(c => c.id === e.target.value))}
        className={`w-full border rounded-xl px-4 py-2.5 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-emerald-500
          ${dark ? 'bg-gray-800 border-gray-700 text-gray-200' : 'bg-white border-gray-300 text-gray-800'}`}
      >
        {pool.map(c => <option key={c.id} value={c.id}>{c.flag} {c.name}</option>)}
      </select>

      {c && (
        <div className={`rounded-2xl border ${dark ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} overflow-hidden`}>
          {/* Header */}
          <div className={`px-6 py-5 border-b ${dark ? 'border-gray-700' : 'border-gray-200'}`}>
            <div className="flex items-center gap-4">
              <span className="text-5xl">{c.flag}</span>
              <div>
                <h2 className={`text-xl font-bold ${dark ? 'text-white' : 'text-gray-900'}`}>{c.name}</h2>
                <p className={`text-sm ${dark ? 'text-gray-400' : 'text-gray-500'}`}>{c.continent}</p>
              </div>
            </div>
          </div>

          {/* Tabs */}
          <div className={`flex border-b ${dark ? 'border-gray-700' : 'border-gray-200'} overflow-x-auto`}>
            {tabs.map(t => (
              <button
                key={t}
                onClick={() => setTab(t)}
                className={`px-4 py-2.5 text-sm font-medium whitespace-nowrap transition-all
                  ${tab === t
                    ? 'border-b-2 border-emerald-500 text-emerald-500'
                    : dark ? 'text-gray-400 hover:text-gray-200' : 'text-gray-500 hover:text-gray-800'
                  }`}
              >
                {tabLabel[t]}
              </button>
            ))}
          </div>

          {/* Content */}
          <div className="p-6 space-y-6">
            {tab === 'overview' && (
              <>
                <Section title="Quick Tells" items={c.quickTells} />
                {c.mixups.length > 0 && (
                  <div className="space-y-2">
                    <h4 className={`text-xs font-bold uppercase tracking-wider ${dark ? 'text-gray-500' : 'text-gray-400'}`}>Common Mix-ups</h4>
                    {c.mixups.slice(0,3).map((m,i) => (
                      <div key={i} className={`rounded-xl p-3 text-sm ${dark ? 'bg-gray-700/60' : 'bg-gray-50'}`}>
                        <span className="font-semibold text-orange-400">{m.country || '?'}</span>
                        {m.clue && <span className={` ml-2 ${dark ? 'text-gray-400' : 'text-gray-600'}`}>— {m.clue}</span>}
                      </div>
                    ))}
                  </div>
                )}
                <Section title="Extra Notes" items={c.extraNotes} />
              </>
            )}
            {tab === 'tells' && <Section title="Quick Tells" items={c.quickTells} />}
            {tab === 'language' && (
              <Section title="Language & Script"
                items={c.languageBullets.length ? c.languageBullets : undefined}
                prose={!c.languageBullets.length ? c.languageScript : undefined} />
            )}
            {tab === 'roads' && (
              <Section title="Roads & Signs"
                items={c.roadsBullets.length ? c.roadsBullets : undefined}
                prose={!c.roadsBullets.length ? c.roadsScript : undefined} />
            )}
            {tab === 'car' && (
              <Section title="Google Car"
                items={c.carBullets.length ? c.carBullets : undefined}
                prose={!c.carBullets.length ? c.googleCar : undefined} />
            )}
            {tab === 'mixups' && c.mixups.length > 0 && (
              <div className="space-y-3">
                {c.mixups.map((m,i) => (
                  <div key={i} className={`rounded-2xl p-4 ${dark ? 'bg-gray-700/60' : 'bg-gray-50'}`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-orange-400 font-bold text-sm">vs {m.country}</span>
                    </div>
                    <p className={`text-sm leading-relaxed ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{m.clue}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── STATS DASHBOARD ─────────────────────────────────────────────────────────
function StatsDashboard({ stats, dark, onReset }) {
  const accuracy = stats.totalAnswered > 0
    ? Math.round((stats.totalCorrect / stats.totalAnswered) * 100)
    : 0;

  const topWrong = Object.entries(stats.wrongHistory || {})
    .sort((a,b) => b[1] - a[1])
    .slice(0, 8)
    .map(([id, count]) => {
      const c = COUNTRIES.find(x => x.id === id);
      return { country: c, count };
    })
    .filter(x => x.country);

  const cardBg = dark ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200';
  const labelColor = dark ? 'text-gray-400' : 'text-gray-500';
  const valColor = dark ? 'text-white' : 'text-gray-900';

  return (
    <div className="space-y-6">
      {/* Overall stats */}
      <div className={`rounded-2xl border ${cardBg} p-6`}>
        <h3 className={`text-sm font-bold uppercase tracking-wider mb-4 ${labelColor}`}>Overall Performance</h3>
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <div className={`text-3xl font-bold text-emerald-500`}>{stats.totalAnswered}</div>
            <div className={`text-xs ${labelColor} mt-1`}>Answered</div>
          </div>
          <div>
            <div className={`text-3xl font-bold ${valColor}`}>{accuracy}%</div>
            <div className={`text-xs ${labelColor} mt-1`}>Accuracy</div>
          </div>
          <div>
            <div className={`text-3xl font-bold text-blue-400`}>{stats.totalCorrect}</div>
            <div className={`text-xs ${labelColor} mt-1`}>Correct</div>
          </div>
        </div>
      </div>

      {/* Mode breakdown */}
      {Object.keys(stats.modeScores || {}).length > 0 && (
        <div className={`rounded-2xl border ${cardBg} p-6`}>
          <h3 className={`text-sm font-bold uppercase tracking-wider mb-4 ${labelColor}`}>By Mode</h3>
          <div className="space-y-3">
            {Object.entries(stats.modeScores).map(([mode, s]) => {
              const modeInfo = MODES.find(m => m.id === mode);
              const acc = s.total > 0 ? Math.round((s.correct / s.total) * 100) : 0;
              return (
                <div key={mode} className="flex items-center gap-3">
                  <span className="text-lg">{modeInfo?.icon || '?'}</span>
                  <span className={`text-sm flex-1 ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{modeInfo?.label || mode}</span>
                  <span className={`text-xs ${labelColor}`}>{s.correct}/{s.total}</span>
                  <div className={`w-20 h-2 rounded-full ${dark ? 'bg-gray-700' : 'bg-gray-200'}`}>
                    <div className="h-2 rounded-full bg-emerald-500 transition-all" style={{width: `${acc}%`}} />
                  </div>
                  <span className={`text-xs font-bold w-8 text-right ${
                    acc >= 80 ? 'text-emerald-400' : acc >= 60 ? 'text-yellow-400' : 'text-red-400'
                  }`}>{acc}%</span>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Countries to review */}
      {topWrong.length > 0 && (
        <div className={`rounded-2xl border ${cardBg} p-6`}>
          <h3 className={`text-sm font-bold uppercase tracking-wider mb-4 ${labelColor}`}>Review These Countries</h3>
          <div className="grid grid-cols-2 gap-2">
            {topWrong.map(({ country: c, count }) => (
              <div key={c.id} className={`flex items-center gap-3 rounded-xl p-3 ${dark ? 'bg-gray-700/60' : 'bg-gray-50'}`}>
                <span className="text-xl">{c.flag}</span>
                <span className={`text-sm flex-1 ${dark ? 'text-gray-300' : 'text-gray-700'}`}>{c.name}</span>
                <span className="text-xs text-red-400 font-bold">✗{count}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      <button
        onClick={onReset}
        className="w-full py-2.5 rounded-xl text-sm text-red-400 border border-red-500/30 hover:bg-red-500/10 transition-all"
      >
        Reset All Stats
      </button>
    </div>
  );
}

// ─── EMPTY STATE ──────────────────────────────────────────────────────────────
