const US_REGIONS = ['All','Northeast','Southeast','South','Midwest','Southwest','West'];

const US_MODES = [
  { id:'capital',   label:'Capital',    icon:'🏛️', desc:'Name → Capital city' },
  { id:'abbr',      label:'Abbrev.',    icon:'🔤', desc:'Name → State abbreviation' },
  { id:'region',    label:'Region',     icon:'🗺️', desc:'Name → Geographic region' },
  { id:'geo',       label:'GeoTells',   icon:'🔍', desc:'Visual tells → State name' },
  { id:'neighbor',  label:'Neighbors',  icon:'🤝', desc:'Which state borders this one?' },
];

function shuffleArr(arr) {
  const a = [...arr];
  for (let i = a.length-1; i > 0; i--) {
    const j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]] = [a[j],a[i]];
  }
  return a;
}

function generateStateQuestion(usMode, pool, stateWrongHistory = {}) {
  if (!pool.length) return null;

  // weighted selection
  let target;
  const weighted = [];
  for (const s of pool) {
    const w = (stateWrongHistory[s.id] || 0) + 1;
    for (let i = 0; i < w; i++) weighted.push(s);
  }
  target = weighted[Math.floor(Math.random() * weighted.length)];

  const others = shuffleArr(pool.filter(s => s.id !== target.id));

  if (usMode === 'capital') {
    const distractors = others.slice(0,3);
    const choices = shuffleArr([target, ...distractors]);
    return {
      target, choices, correctIdx: choices.indexOf(target),
      prompt: `What is the capital of ${target.name}?`,
      display: { type: 'prose', content: [`State: ${target.name} (${target.abbr})
Region: ${target.region}`] },
      getLabel: s => s.capital,
      explanation: `${target.name}'s capital is ${target.capital}.`,
    };
  }

  if (usMode === 'abbr') {
    // pick distractors with similar-looking abbreviations when possible
    const distractors = others.slice(0,3);
    const choices = shuffleArr([target, ...distractors]);
    return {
      target, choices, correctIdx: choices.indexOf(target),
      prompt: `What is the two-letter abbreviation for ${target.name}?`,
      display: { type: 'prose', content: [`State: ${target.name}
Capital: ${target.capital} | Region: ${target.region}`] },
      getLabel: s => s.abbr,
      explanation: `${target.name} → ${target.abbr}`,
    };
  }

  if (usMode === 'region') {
    // pick distractors from different regions to make it interesting
    const regionsLeft = US_REGIONS.filter(r => r !== 'All' && r !== target.region);
    const wrongChoices = regionsLeft.slice(0,3);
    // But we're choosing from state objects — use states from other regions as answer options display
    const distractors = others.filter(s => s.region !== target.region).slice(0,3);
    const choices = shuffleArr([target, ...distractors]);
    return {
      target, choices, correctIdx: choices.indexOf(target),
      prompt: `Which region is ${target.name} in?`,
      display: { type: 'prose', content: [`State: ${target.name} (${target.abbr})
Capital: ${target.capital}`] },
      getLabel: s => s.region,
      explanation: `${target.name} is in the ${target.region}.`,
    };
  }

  if (usMode === 'geo') {
    const distractors = others.slice(0,3);
    const choices = shuffleArr([target, ...distractors]);
    return {
      target, choices, correctIdx: choices.indexOf(target),
      prompt: 'Which US state do these Street View tells describe?',
      display: { type: 'bullets', content: target.geo.split('. ').filter(Boolean).slice(0,4) },
      getLabel: s => s.name,
      explanation: target.geo,
    };
  }

  if (usMode === 'neighbor') {
    if (!target.neighbors.length) {
      // Alaska/Hawaii have no neighbors — skip to geo mode
      return generateStateQuestion('geo', pool, stateWrongHistory);
    }
    const neighborAbbr = target.neighbors[Math.floor(Math.random() * target.neighbors.length)];
    const neighborState = US_STATES.find(s => s.abbr === neighborAbbr);
    if (!neighborState) return generateStateQuestion('geo', pool, stateWrongHistory);
    const distractors = shuffleArr(pool.filter(s => s.id !== target.id && s.id !== neighborState?.id)).slice(0,2);
    const choices = shuffleArr([target, neighborState, ...distractors]);
    return {
      target: neighborState, choices, correctIdx: choices.indexOf(neighborState),
      prompt: `Which state directly borders ${target.name} (${target.abbr})?`,
      display: { type: 'prose', content: [`${target.name} has ${target.neighbors.length} neighboring state${target.neighbors.length !== 1 ? 's' : ''}: ${target.neighbors.join(', ')}`] },
      getLabel: s => `${s.name} (${s.abbr})`,
      explanation: `${target.name} borders: ${target.neighbors.join(', ')}. ${neighborState.name} is one of them.`,
    };
  }

  return null;
}

// ─── US STATES QUIZ COMPONENT ─────────────────────────────────────────────────
function USStatesQuiz({ dark }) {
  const [usMode, setUsMode] = useState('geo');
  const [regionFilter, setRegionFilter] = useState('All');
  const [question, setQuestion] = useState(null);
  const [selected, setSelected] = useState(null);
  const [showResult, setShowResult] = useState(false);
  const [sessionScore, setSessionScore] = useState({ correct: 0, total: 0 });
  const [streak, setStreak] = useState(0);
  const [stateWrongHistory, setStateWrongHistory] = useState(() => {
    try { return JSON.parse(localStorage.getItem('us_states_wrong') || '{}'); } catch { return {}; }
  });

  const pool = useMemo(() => {
    let p = US_STATES;
    if (regionFilter !== 'All') p = p.filter(s => s.region === regionFilter);
    // Exclude states with no neighbors from neighbor mode display
    return p;
  }, [regionFilter]);

  const nextQ = useCallback(() => {
    const q = generateStateQuestion(usMode, pool, stateWrongHistory);
    setQuestion(q);
    setSelected(null);
    setShowResult(false);
  }, [usMode, pool, stateWrongHistory]);

  useEffect(() => { if (pool.length) nextQ(); }, [usMode, regionFilter, pool.length]);

  const handleSelect = useCallback((idx) => {
    if (showResult || !question) return;
    setSelected(idx);
    setShowResult(true);
    const correct = idx === question.correctIdx;
    setSessionScore(s => ({ correct: s.correct + (correct ? 1 : 0), total: s.total + 1 }));
    setStreak(s => correct ? s + 1 : 0);
    if (!correct) {
      setStateWrongHistory(prev => {
        const next = { ...prev, [question.target.id]: (prev[question.target.id] || 0) + 1 };
        try { localStorage.setItem('us_states_wrong', JSON.stringify(next)); } catch {}
        return next;
      });
    }
  }, [showResult, question]);

  const cardBg = dark ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200';
  const textMuted = dark ? 'text-gray-400' : 'text-gray-500';

  return (
    <div className="space-y-4">
      {/* Mode selector */}
      <div className="flex gap-2 overflow-x-auto pb-0.5 scrollbar-none">
        {US_MODES.map(m => (
          <button
            key={m.id}
            onClick={() => setUsMode(m.id)}
            className={`flex flex-col items-center gap-0.5 px-3 py-2 rounded-xl text-xs font-medium transition-all flex-shrink-0
              ${usMode === m.id
                ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/30'
                : dark
                  ? 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-gray-200'
                  : 'bg-white text-gray-500 hover:bg-gray-100 hover:text-gray-800 border border-gray-200'
              }`}
          >
            <span className="text-base">{m.icon}</span>
            <span>{m.label}</span>
          </button>
        ))}
      </div>

      {/* Region filter */}
      <div className="flex gap-1.5 flex-wrap">
        {US_REGIONS.map(r => (
          <button
            key={r}
            onClick={() => setRegionFilter(r)}
            className={`px-3 py-1 rounded-full text-xs font-semibold transition-all
              ${regionFilter === r
                ? 'bg-blue-500 text-white'
                : dark ? 'bg-gray-800 text-gray-400 hover:text-gray-200' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
          >
            {r}
          </button>
        ))}
      </div>

      {/* Session score */}
      {sessionScore.total > 0 && (
        <div className="flex items-center justify-between text-sm">
          <span className={textMuted}>
            Score: <span className="font-bold text-blue-400">{sessionScore.correct}/{sessionScore.total}</span>
            <span className={`ml-2 ${textMuted}`}>{Math.round(sessionScore.correct/sessionScore.total*100)}%</span>
          </span>
          {streak > 1 && <span className="font-bold text-orange-400">🔥 {streak}</span>}
        </div>
      )}

      {/* Question */}
      {!question ? (
        <div className={`text-center py-16 ${textMuted}`}>
          <div className="text-4xl mb-2">🇺🇸</div>
          <p>No states match this filter.</p>
        </div>
      ) : (
        <div className="space-y-4">
          <div className={`text-sm font-medium ${textMuted}`}>{question.prompt}</div>

          {/* Display */}
          <DisplayCard display={question.display} dark={dark} />

          {/* Choices */}
          <div className="grid grid-cols-2 gap-3">
            {question.choices.map((s, i) => {
              const isCorrect = i === question.correctIdx;
              const isSelected = i === selected;
              let style = dark
                ? 'bg-gray-800 border-gray-700 text-gray-200 hover:bg-gray-700 hover:border-gray-500'
                : 'bg-white border-gray-200 text-gray-800 hover:bg-gray-50 hover:border-gray-400';
              if (showResult) {
                if (isCorrect) style = 'bg-blue-500/20 border-blue-500 text-blue-400';
                else if (isSelected && !isCorrect) style = 'bg-red-500/20 border-red-500 text-red-400';
                else style = dark ? 'bg-gray-800/50 border-gray-700/50 text-gray-500' : 'bg-gray-50 border-gray-200 text-gray-400';
              }
              return (
                <button
                  key={i}
                  onClick={() => !showResult && handleSelect(i)}
                  disabled={showResult}
                  className={`border-2 rounded-2xl px-4 py-3 text-sm font-medium text-left transition-all
                    flex items-center gap-2 ${style} ${!showResult ? 'cursor-pointer active:scale-95' : 'cursor-default'}`}
                >
                  <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${dark ? 'bg-gray-700' : 'bg-gray-100'}`}>
                    {String.fromCharCode(65+i)}
                  </span>
                  <span className="text-xs leading-tight">{question.getLabel(s)}</span>
                  {showResult && isCorrect && <span className="ml-auto">✓</span>}
                  {showResult && isSelected && !isCorrect && <span className="ml-auto">✗</span>}
                </button>
              );
            })}
          </div>

          {/* Feedback */}
          {showResult && (
            <div className={`rounded-2xl p-4 border-2 ${
              selected === question.correctIdx
                ? 'bg-blue-500/10 border-blue-500/50'
                : 'bg-red-500/10 border-red-500/50'
            }`}>
              <div className="flex items-center gap-2 mb-1">
                <span className="text-xl">{selected === question.correctIdx ? '✅' : '❌'}</span>
                <span className={`font-bold ${selected === question.correctIdx ? 'text-blue-400' : 'text-red-400'}`}>
                  {selected === question.correctIdx ? 'Correct!' : `Wrong — ${question.getLabel(question.target)}`}
                </span>
              </div>
              {question.explanation && (
                <p className={`text-xs leading-relaxed mt-1 ${textMuted}`}>{question.explanation}</p>
              )}
            </div>
          )}

          {showResult ? (
            <button
              onClick={nextQ}
              className="w-full bg-blue-500 hover:bg-blue-400 active:scale-95 text-white font-semibold py-3.5 rounded-2xl transition-all shadow-lg shadow-blue-500/20"
            >
              Next Question →
            </button>
          ) : (
            <button
              onClick={nextQ}
              className={`w-full py-2.5 rounded-xl text-sm transition-all ${textMuted} hover:text-gray-300`}
            >
              Skip
            </button>
          )}
        </div>
      )}

      {/* Most missed */}
      {Object.keys(stateWrongHistory).length > 0 && (
        <div className={`rounded-2xl border ${cardBg} p-4`}>
          <h3 className={`text-xs font-bold uppercase tracking-wider mb-3 ${textMuted}`}>States to Review</h3>
          <div className="flex flex-wrap gap-2">
            {Object.entries(stateWrongHistory)
              .sort((a,b) => b[1]-a[1])
              .slice(0,10)
              .map(([id, count]) => {
                const s = US_STATES.find(x => x.id === id);
                if (!s) return null;
                return (
                  <span key={id} className={`px-2 py-1 rounded-lg text-xs ${dark ? 'bg-gray-700 text-gray-300' : 'bg-gray-100 text-gray-700'}`}>
                    {s.abbr} <span className="text-red-400 font-bold">✗{count}</span>
                  </span>
                );
              })}
          </div>
          <button
            onClick={() => { setStateWrongHistory({}); localStorage.removeItem('us_states_wrong'); }}
            className={`mt-3 text-xs ${textMuted} hover:text-red-400 transition-colors`}
          >
            Reset state history
          </button>
        </div>
      )}
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
function App() {
  const [dark, setDark] = useState(true);
  const [mode, setMode] = useState('tells');
  const [continent, setContinent] = useState('All');
  const [difficulty, setDifficulty] = useState('All');
  const [view, setView] = useState('quiz'); // 'quiz' | 'stats' | 'deepdive' | 'usstates'
  const [roadsSubMode, setRoadsSubMode] = useState('all');

  // Quiz state
  const [question, setQuestion] = useState(null);
  const [selected, setSelected] = useState(null);
  const [showResult, setShowResult] = useState(false);
  const [sessionScore, setSessionScore] = useState({ correct: 0, total: 0 });
  const [streak, setStreak] = useState(0);
  const [qNum, setQNum] = useState(0);

  // Persistent stats
  const [stats, setStats] = useState(loadStats);
  useEffect(() => saveStats(stats), [stats]);

  const pool = useMemo(
    () => getPool(continent, difficulty, mode, roadsSubMode),
    [continent, difficulty, mode, roadsSubMode]
  );

  const nextQuestion = useCallback(() => {
    const q = generateQuestion(mode, pool, stats.wrongHistory, roadsSubMode);
    setQuestion(q);
    setSelected(null);
    setShowResult(false);
    setQNum(n => n + 1);
  }, [mode, pool, stats.wrongHistory, roadsSubMode]);

  // Auto-generate first question
  useEffect(() => {
    if ((view === 'quiz') && pool.length > 0) {
      nextQuestion();
    }
  }, [mode, continent, difficulty, view, pool.length]);

  const handleSelect = useCallback((idx) => {
    if (showResult || !question) return;
    setSelected(idx);
    setShowResult(true);

    const correct = idx === question.correctIdx;
    const newScore = {
      correct: sessionScore.correct + (correct ? 1 : 0),
      total: sessionScore.total + 1,
    };
    setSessionScore(newScore);
    setStreak(s => correct ? s + 1 : 0);

    setStats(prev => {
      const modeKey = question.mode || mode;
      const modeScores = { ...prev.modeScores };
      modeScores[modeKey] = {
        correct: (modeScores[modeKey]?.correct || 0) + (correct ? 1 : 0),
        total: (modeScores[modeKey]?.total || 0) + 1,
      };
      const wrongHistory = { ...prev.wrongHistory };
      if (!correct) {
        wrongHistory[question.target.id] = (wrongHistory[question.target.id] || 0) + 1;
      }
      return {
        totalAnswered: prev.totalAnswered + 1,
        totalCorrect: prev.totalCorrect + (correct ? 1 : 0),
        modeScores,
        wrongHistory,
      };
    });
  }, [showResult, question, sessionScore, mode]);

  const bg = dark ? 'bg-gray-900 text-gray-100' : 'bg-gray-50 text-gray-900';
  const headerBg = dark ? 'bg-gray-900/95 border-gray-800' : 'bg-white/95 border-gray-200';

  return (
    <div className={`min-h-screen ${bg} font-sans`}>
      {/* Header */}
      <header className={`sticky top-0 z-10 border-b backdrop-blur ${headerBg}`}>
        <div className="max-w-2xl mx-auto px-4 py-3">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <span className="text-2xl">🌍</span>
              <div>
                <h1 className={`text-base font-bold leading-tight ${dark ? 'text-white' : 'text-gray-900'}`}>
                  GeoGuessr Meta
                </h1>
                <p className={`text-xs ${dark ? 'text-gray-500' : 'text-gray-400'}`}>
                  {COUNTRIES.length} countries
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button
                onClick={() => setView(v => v === 'stats' ? 'quiz' : 'stats')}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all
                  ${view === 'stats'
                    ? 'bg-emerald-500 text-white'
                    : dark ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
              >
                📊 Stats
              </button>
              <button
                onClick={() => setView(v => v === 'deepdive' ? 'quiz' : 'deepdive')}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all
                  ${view === 'deepdive'
                    ? 'bg-emerald-500 text-white'
                    : dark ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
              >
                📚 Study
              </button>
              <button
                onClick={() => setView(v => v === 'usstates' ? 'quiz' : 'usstates')}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all
                  ${view === 'usstates'
                    ? 'bg-blue-500 text-white'
                    : dark ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
              >
                🇺🇸 States
              </button>
              <button
                onClick={() => setDark(d => !d)}
                className={`w-9 h-9 rounded-xl flex items-center justify-center text-base transition-all
                  ${dark ? 'bg-gray-800 text-yellow-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
              >
                {dark ? '☀️' : '🌙'}
              </button>
            </div>
          </div>

          {/* Mode selector */}
          {view === 'quiz' && (
            <div className="flex gap-2 overflow-x-auto pb-0.5 scrollbar-none">
              {MODES.filter(m => m.id !== 'deepdive').map(m => (
                <ModeButton key={m.id} mode={m} current={mode} onClick={setMode} dark={dark} />
              ))}
            </div>
          )}
          {/* Roads sub-mode selector */}
          {view === 'quiz' && mode === 'roads' && (
            <div className="flex gap-1.5 overflow-x-auto pb-0.5 scrollbar-none mt-1">
              {ROAD_SUBMODES.map(s => (
                <button
                  key={s.id}
                  onClick={() => setRoadsSubMode(s.id)}
                  className={`px-3 py-1 rounded-full text-xs font-semibold whitespace-nowrap transition-all
                    ${roadsSubMode === s.id
                      ? 'bg-emerald-500 text-white shadow-sm'
                      : dark ? 'bg-gray-800 text-gray-400 hover:text-gray-200' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          )}
        </div>
      </header>

      {/* Main content */}
      <main className="max-w-2xl mx-auto px-4 py-5 space-y-4">
        {view === 'stats' ? (
          <StatsDashboard
            stats={stats}
            dark={dark}
            onReset={() => {
              setStats({ totalAnswered: 0, totalCorrect: 0, modeScores: {}, wrongHistory: {} });
            }}
          />
        ) : view === 'deepdive' ? (
          <>
            <FilterBar continent={continent} setContinent={setContinent} difficulty={difficulty} setDifficulty={setDifficulty} dark={dark} />
            <DeepDive pool={getPool(continent, difficulty, 'tells')} dark={dark} />
          </>
        ) : view === 'usstates' ? (
          <USStatesQuiz dark={dark} />
        ) : (
          <>
            {/* Filters */}
            <FilterBar continent={continent} setContinent={setContinent} difficulty={difficulty} setDifficulty={setDifficulty} dark={dark} />

            {/* Session stats bar */}
            {sessionScore.total > 0 && (
              <SessionBar score={sessionScore} streak={streak} qNum={qNum} dark={dark} />
            )}

            {/* Quiz area */}
            {pool.length === 0 ? (
              <EmptyState mode={mode} continent={continent} dark={dark} />
            ) : question ? (
              <div className="space-y-4">
                {/* Question prompt */}
                <div className={`text-sm font-medium ${dark ? 'text-gray-400' : 'text-gray-500'}`}>
                  {question.prompt}
                </div>

                {/* Display */}
                <DisplayCard display={question.display} dark={dark} />

                {/* Choices */}
                <ChoiceGrid
                  choices={question.choices}
                  correctIdx={question.correctIdx}
                  selected={selected}
                  onSelect={handleSelect}
                  dark={dark}
                  showResult={showResult}
                  questionMode={question.mode}
                />

                {/* Feedback */}
                {showResult && (
                  <FeedbackPanel question={question} selected={selected} dark={dark} />
                )}

                {/* Next button */}
                {showResult && (
                  <button
                    onClick={nextQuestion}
                    className="w-full bg-emerald-500 hover:bg-emerald-400 active:scale-95 text-white font-semibold py-3.5 rounded-2xl transition-all shadow-lg shadow-emerald-500/20"
                  >
                    Next Question →
                  </button>
                )}

                {/* Skip */}
                {!showResult && (
                  <button
                    onClick={nextQuestion}
                    className={`w-full py-2.5 rounded-xl text-sm transition-all
                      ${dark ? 'text-gray-600 hover:text-gray-400' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    Skip
                  </button>
                )}
              </div>
            ) : (
              <div className={`text-center py-16 ${dark ? 'text-gray-500' : 'text-gray-400'}`}>
                Loading...
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}
